```class Solution {
    public int hardestWorker(int n, int[][] logs) {
        int result = logs[0][0];
        for (int i = 1; i < logs.length; i++) {
            if (logs[i][0] > result) {
                result = logs[i][0];
            }
        }
        return result;
    }
}
